#include <stdio.h>
#include <string.h>

void compareInt(int a, int b) {
    if (a > b) printf("%d\n", a);
    else if (b > a) printf("%d\n", b);
    else printf("Equal\n");
}

void compareChar(char a, char b) {
    if (a > b) printf("%c\n", a);
    else if (b > a) printf("%c\n", b);
    else printf("Equal\n");
}

void compareStr(const char *a, const char *b) {
    int res = strcmp(a, b);
    if (res > 0) printf("%s\n", a);
    else if (res < 0) printf("%s\n", b);
    else printf("Equal\n");
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int i1, i2; char c1, c2; char s1[105], s2[105];
        scanf("%d %d", &i1, &i2);
        scanf(" %c %c", &c1, &c2);
        scanf(" %s %s", s1, s2);
        compareInt(i1, i2);
        compareChar(c1, c2);
        compareStr(s1, s2);
    }
    return 0;
}

