code.Java:
import java.util.*;

class Comparator {
    void compare(int a, int b) {
        if (a > b) System.out.println(a);
        else if (b > a) System.out.println(b);
        else System.out.println("Equal");
    }
    void compare(char a, char b) {
        if (a > b) System.out.println(a);
        else if (b > a) System.out.println(b);
        else System.out.println("Equal");
    }
    void compare(String a, String b) {
        int res = a.compareTo(b);
        if (res > 0) System.out.println(a);
        else if (res < 0) System.out.println(b);
        else System.out.println("Equal");
    }
}

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int i1 = sc.nextInt();
            int i2 = sc.nextInt();
            char c1 = sc.next().charAt(0);
            char c2 = sc.next().charAt(0);
            String s1 = sc.next();
            String s2 = sc.next();
            Comparator cmp = new Comparator();
            cmp.compare(i1, i2);
            cmp.compare(c1, c2);
            cmp.compare(s1, s2);
        }
        sc.close();
    }
}

code.Python3:
import sys

def compare_int(a, b):
    if a > b:
        return str(a)
    if b > a:
        return str(b)
    return "Equal"

def compare_char(a, b):
    if a > b:
        return a
    if b > a:
        return b
    return "Equal"

def compare_str(a, b):
    if a > b:
        return a
    if b > a:
        return b
    return "Equal"

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        i1 = int(next(it)); i2 = int(next(it))
        c1 = next(it); c2 = next(it)
        s1 = next(it); s2 = next(it)
        out.append(compare_int(i1, i2))
        out.append(compare_char(c1, c2))
        out.append(compare_str(s1, s2))
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

